#include <stdio.h>
#include <math.h>
#define MAX 100
int main() {
    int T, S, C;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &S, &C);
        int accessPoints[S][3];
        int computers[C][2];
        for (int i = 0; i < S; i++) {
            scanf("%d %d %d", &accessPoints[i][0], &accessPoints[i][1], &accessPoints[i][2]);
        }
        for (int i = 0; i < C; i++) {
            scanf("%d %d", &computers[i][0], &computers[i][1]);
        }
        // Calculate distances and assign computers to access points
        for (int i = 0; i < C; i++) {
            double maxDistance = 0;
            for (int j = 0; j < S; j++) {
                double distance = sqrt(pow(computers[i][0] - accessPoints[j][0], 2) + pow(computers[i][1] - accessPoints[j][1], 2));
                if (distance > maxDistance) {
                    maxDistance = distance;
                }
            }
            printf("%.3f\n", maxDistance);
        }
        printf("\n");
    }
    return 0;
}

