code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int S = scanner.nextInt();
            int C = scanner.nextInt();
            int[][] accessPoints = new int[S][3];
            int[][] computers = new int[C][2];
            for (int i = 0; i < S; i++) {
                accessPoints[i][0] = scanner.nextInt();
                accessPoints[i][1] = scanner.nextInt();
                accessPoints[i][2] = scanner.nextInt();
            }
            for (int i = 0; i < C; i++) {
                computers[i][0] = scanner.nextInt();
                computers[i][1] = scanner.nextInt();
            }
            // Calculate distances and assign computers to access points
            for (int i = 0; i < C; i++) {
                double maxDistance = 0;
                for (int j = 0; j < S; j++) {
                    double distance = Math.sqrt(Math.pow(computers[i][0] - accessPoints[j][0], 2) + Math.pow(computers[i][1] - accessPoints[j][1], 2));
                    if (distance > maxDistance) {
                        maxDistance = distance;
                    }
                }
                System.out.printf("%.3f\n", maxDistance);
            }
            System.out.println();
        }
    }
}

