const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [S, C] = readline().split(' ').map(Number);
    const accessPoints = [];
    for (let j = 0; j < S; j++) {
        accessPoints.push(readline().split(' ').map(Number));
    }
    const computers = [];
    for (let j = 0; j < C; j++) {
        computers.push(readline().split(' ').map(Number));
    }
    // Calculate distances and assign computers to access points
    for (let j = 0; j < C; j++) {
        let maxDistance = 0;
        for (let k = 0; k < S; k++) {
            const distance = Math.sqrt(Math.pow(computers[j][0] - accessPoints[k][0], 2) + Math.pow(computers[j][1] - accessPoints[k][1], 2));
            if (distance > maxDistance) {
                maxDistance = distance;
            }
        }
        console.log(maxDistance.toFixed(3));
    }
    console.log();
}

